import './index.css';

import {
  useEffect,
  useState
} from 'react';

import {
  useNavigate
} from 'react-router-dom';

import {
  createSubject,
  getSubjects
} from '../../services/subjectService';

function SubjectManagementPage() {

  const navigate =
    useNavigate();

  const [subjects, setSubjects] =
    useState([]);

  const [loading, setLoading] =
    useState(true);

  const [formData, setFormData] =
    useState({
      subject_name: '',
      semester: ''
    });

  // Load Subjects
  const loadSubjects =
    async () => {

    try {

      setLoading(true);

      const data =
        await getSubjects();

      setSubjects(data);

    } catch (error) {

      console.log(error);

      // Invalid Token
      if (
        error.response?.status === 403
      ) {

        alert(
          'Session Expired. Login Again'
        );

        localStorage.removeItem(
          'token'
        );

        localStorage.removeItem(
          'user'
        );

        navigate('/');

      }

    } finally {

      setLoading(false);

    }

  };

  useEffect(() => {

    loadSubjects();

  }, []);

  // Input Change
  const handleChange =
    (e) => {

    setFormData({
      ...formData,
      [e.target.name]:
      e.target.value
    });

  };

  // Create Subject
  const handleSubmit =
    async (e) => {

    e.preventDefault();

    try {

      await createSubject(formData);

      alert(
        'Subject Created Successfully'
      );

      setFormData({
        subject_name: '',
        semester: ''
      });

      loadSubjects();

    } catch (error) {

      console.log(error);

      if (
        error.response?.status === 403
      ) {

        alert(
          'Invalid Token. Login Again'
        );

        navigate('/');

      } else {

        alert(
          error.response?.data?.message ||
          'Something Went Wrong'
        );

      }

    }

  };

  return (

    <div className="subject-page">

      <div className="subject-header">

        <h1>
          Subject Management
        </h1>

      </div>

      {/* FORM */}

      <form
        className="subject-form"
        onSubmit={handleSubmit}
      >

        <input
          type="text"
          name="subject_name"
          placeholder="Enter Subject Name"
          value={formData.subject_name}
          onChange={handleChange}
          required
        />

        <input
          type="number"
          name="semester"
          placeholder="Enter Semester"
          value={formData.semester}
          onChange={handleChange}
          required
        />

        <button type="submit">
          Create Subject
        </button>

      </form>

      {/* SUBJECT LIST */}

      {
        loading
        ? (
          <h2>
            Loading Subjects...
          </h2>
        )
        : (
          <div className="subject-list">

            {
              subjects.length > 0
              ? (
                subjects.map((subject) => (

                  <div
                    key={subject.id}
                    className="subject-card"
                  >

                    <h3>
                      {subject.subject_name}
                    </h3>

                    <p>
                      Semester:
                      {subject.semester}
                    </p>

                  </div>

                ))
              )
              : (
                <h3>
                  No Subjects Found
                </h3>
              )
            }

          </div>
        )
      }

    </div>

  );

}

export default SubjectManagementPage;
